import { createAgentSession, pollAgentSessionEvents, } from "../agentSessionChannel.js";
import { reportHandoff } from "../analytics.js";
import { getConfig, hasCredentials } from "../config.js";
import { recordFocus } from "../frontmostApp.js";
import { StudioNavigationError, withStudioSession, } from "../withStudioSession.js";
function emitJson(event) {
    process.stdout.write(`${JSON.stringify(event)}\n`);
}
/**
 * Open the per-dataset review page in Studio and stay alive until the user
 * clicks Done (or the session ends). Stdout is a JSON line stream:
 *
 *   {"event":"modify","datasetId":"...","ts":"..."}     // non-terminal
 *   {"event":"saved","status":"saved"}                  // terminal
 *   {"event":"cancelled","status":"cancelled"}          // terminal
 *
 * After a terminal event the process exits 0. The calling agent reads stdout
 * incrementally, reacting to each modify event by doing add/remove work.
 *
 * Free-form logs go to stderr so stdout stays a parseable JSONL stream.
 */
export async function runStartDataset(platform, pluginVersion) {
    const args = process.argv.slice(2);
    const functionKey = args[0];
    const datasetId = args[1];
    if (!functionKey || !datasetId) {
        console.error("Usage: startDataset <functionKey> <datasetId>");
        console.error("Both arguments are required.");
        process.exit(1);
    }
    if (!hasCredentials()) {
        console.error(`Not authenticated. Run ${platform.loginHint} first.`);
        process.exit(1);
    }
    const config = getConfig();
    if (!config.apiKey) {
        console.error("API key missing in config.");
        process.exit(1);
    }
    const apiKey = config.apiKey;
    const restoreFocus = recordFocus();
    const targetPath = `/studio/trace-functions/${encodeURIComponent(functionKey)}/datasets/${encodeURIComponent(datasetId)}`;
    let sessionId;
    try {
        const result = await withStudioSession({
            apiKey,
            serviceUrl: config.serviceUrl,
            targetPath,
        });
        sessionId = result.sessionId;
    }
    catch (err) {
        if (err instanceof StudioNavigationError) {
            console.error(`Studio navigation failed: ${err.message}`);
        }
        else {
            console.error(`Failed to open Studio: ${err.message}`);
        }
        process.exit(1);
    }
    try {
        await createAgentSession({
            serviceUrl: config.serviceUrl,
            apiKey,
            sessionId,
        });
    }
    catch (err) {
        console.error(`agent-event session bind failed (edit forwarding disabled): ${err.message}`);
    }
    const agentAbort = new AbortController();
    const pollerPromise = pollAgentSessionEvents({
        serviceUrl: config.serviceUrl,
        apiKey,
        sessionId,
        abortSignal: agentAbort.signal,
        onEvent: (event) => {
            if (event.type === "studio:edit-with-agent") {
                emitJson({
                    event: "modify",
                    datasetId: event.data.datasetId,
                    ts: new Date().toISOString(),
                });
                restoreFocus();
                return;
            }
            if (event.type === "studio:return-to-agent") {
                emitJson({ event: "saved", status: "saved" });
                console.error("Labeling complete [via studio].");
                agentAbort.abort();
                return;
            }
            if (event.type === "studio:session-ended") {
                emitJson({ event: "cancelled", status: "cancelled" });
                console.error("Labeling ended without saving.");
                agentAbort.abort();
            }
        },
        onError: (err) => {
            console.error(`agent-event poll: ${err.message}`);
        },
    });
    try {
        await pollerPromise;
        await reportHandoff(apiKey, pluginVersion, platform, {
            flow: "dataset.start",
            wonBy: "studio",
            loopbackAvailable: false,
            ticketAvailable: false,
        });
        restoreFocus();
        process.exit(0);
    }
    catch (err) {
        if (agentAbort.signal.aborted) {
            process.exit(0);
        }
        console.error(err.message);
        process.exit(1);
    }
}
